import{_ as e,c as t,o as i,d as a}from"./app.661b9247.js";const g=JSON.parse('{"title":"GitHub仓库实用技巧","description":"","frontmatter":{},"headers":[{"level":2,"title":"1. 使用“T”键快速查找文件","slug":"_1-使用-t-键快速查找文件","link":"#_1-使用-t-键快速查找文件","children":[]},{"level":2,"title":"2. 3种方式在线使用“VSCode”编辑器查看代码","slug":"_2-3种方式在线使用-vscode-编辑器查看代码","link":"#_2-3种方式在线使用-vscode-编辑器查看代码","children":[]},{"level":2,"title":"2.1 使用\\".\\"按键","slug":"_2-1-使用-按键","link":"#_2-1-使用-按键","children":[]},{"level":2,"title":"2.2 使用\\"github1s.com\\"","slug":"_2-2-使用-github1s-com","link":"#_2-2-使用-github1s-com","children":[]},{"level":2,"title":"2.3 使用 “gitpod.com/#xxx”","slug":"_2-3-使用-gitpod-com-xxx","link":"#_2-3-使用-gitpod-com-xxx","children":[]},{"level":2,"title":"3. 链接到单行代码","slug":"_3-链接到单行代码","link":"#_3-链接到单行代码","children":[]},{"level":2,"title":"4. 链接到多行代码","slug":"_4-链接到多行代码","link":"#_4-链接到多行代码","children":[]},{"level":2,"title":"5. 跳转到定义函数的位置","slug":"_5-跳转到定义函数的位置","link":"#_5-跳转到定义函数的位置","children":[]},{"level":2,"title":"6. 查看快捷键列表","slug":"_6-查看快捷键列表","link":"#_6-查看快捷键列表","children":[]}],"relativePath":"Document/GitHub的使用/GitHub仓库实用技巧.md","lastUpdated":1664267725000}'),r={name:"Document/GitHub的使用/GitHub仓库实用技巧.md"},p=a('<h1 id="github仓库实用技巧" tabindex="-1">GitHub仓库实用技巧 <a class="header-anchor" href="#github仓库实用技巧" aria-hidden="true">#</a></h1><h2 id="_1-使用-t-键快速查找文件" tabindex="-1">1. 使用“T”键快速查找文件 <a class="header-anchor" href="#_1-使用-t-键快速查找文件" aria-hidden="true">#</a></h2><p>这个功能实在太赞了，但却只有少部分人知道。当你想看一个文件的内容时，按下“T”键，搜索文件名，竟然能直接跳转到目标文件。</p><p><strong>操作步骤</strong></p><ol><li><p>打开<a href="https://link.juejin.cn/?target=https%3A%2F%2Fgithub.com%2Flodash%2Flodash" target="_blank" rel="noreferrer">github.com/lodash/loda…</a></p></li><li><p>按下“T”键</p></li><li><p>输入<code>add.test.js</code>(任何你想查找的文件)</p></li><li><p>点击跳转查看内容</p></li></ol><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/8a8699f94f154244bb79f3e88528f6a3~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp?" alt=""></p><h2 id="_2-3种方式在线使用-vscode-编辑器查看代码" tabindex="-1">2. 3种方式在线使用“VSCode”编辑器查看代码 <a class="header-anchor" href="#_2-3种方式在线使用-vscode-编辑器查看代码" aria-hidden="true">#</a></h2><p>虽然使用“T”键可以快速搜索文件，但当咱想查看整个项目代码时，它就显得有点效率低下了。</p><p>一起来看看三种在线查看代码的方法，就像在你的VSCode编辑器中一样。</p><p>第三种是我最喜欢的方式，我相信你会喜欢的。</p><h2 id="_2-1-使用-按键" tabindex="-1">2.1 使用&quot;.&quot;按键 <a class="header-anchor" href="#_2-1-使用-按键" aria-hidden="true">#</a></h2><ol><li><p>打开<a href="https://link.juejin.cn/?target=https%3A%2F%2Fgithub.com%2Fvuejs%2Fvue" target="_blank" rel="noreferrer">github.com/vuejs/vue</a></p></li><li><p>按下&quot;.&quot;键</p></li><li><p>接着你会被重定向到 <a href="https://link.juejin.cn/?target=https%3A%2F%2Fgithub.dev%2Fvuejs%2Fvue" target="_blank" rel="noreferrer">github.dev/vuejs/vue</a></p></li><li><p>是不是很爽，和本地vscode一模一样</p></li></ol><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/e8528d08596345c69e8e60fc4b58093d~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp?" alt=""></p><h2 id="_2-2-使用-github1s-com" tabindex="-1">2.2 使用&quot;<a href="http://github1s.com" target="_blank" rel="noreferrer">github1s.com</a>&quot; <a class="header-anchor" href="#_2-2-使用-github1s-com" aria-hidden="true">#</a></h2><p>仅仅需要将“github”更改为“github1s”，咱们就可以达到与方法1相同的效果！</p><ol><li><p>打开 <a href="https://link.juejin.cn/?target=https%3A%2F%2Fgithub.com%2Fvuejs%2Fvue" target="_blank" rel="noreferrer">github.com/vuejs/vue</a></p></li><li><p>将url修改为<a href="https://link.juejin.cn/?target=https%3A%2F%2Fgithub1s.com%2Fvuejs%2Fvue" target="_blank" rel="noreferrer">github1s.com/vuejs/vue</a></p></li><li><p>神奇不...</p></li></ol><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/e96ef7decc344503bd3cfaf50c10388a~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp?" alt=""></p><h2 id="_2-3-使用-gitpod-com-xxx" tabindex="-1">2.3 使用 “<a href="http://gitpod.com/#xxx%E2%80%9D" target="_blank" rel="noreferrer">gitpod.com/#xxx”</a> <a class="header-anchor" href="#_2-3-使用-gitpod-com-xxx" aria-hidden="true">#</a></h2><p>第三种更牛逼了，你甚至可以在线运行js，只需要在<code>gitpod.com/#</code>后添加项目地址就可以达到效果。</p><ol><li><p>打开<a href="https://link.juejin.cn/?target=https%3A%2F%2Fgithub.com%2Fqianlongo%2Ffe-handwriting" target="_blank" rel="noreferrer">github.com/qianlongo/f…</a></p></li><li><p><a href="http://xn--gitpod-hx3jnvg04akcyi884qw4cqs2ao45l.com/#" target="_blank" rel="noreferrer">在地址栏最前面添加gitpod.com/#</a></p></li><li><p>完美...</p></li></ol><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/9994ef41e6b44029ad347dba82cdcdaa~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp?" alt=""></p><h2 id="_3-链接到单行代码" tabindex="-1">3. 链接到单行代码 <a class="header-anchor" href="#_3-链接到单行代码" aria-hidden="true">#</a></h2><p>有时我们希望希望通过一个地址就链接到特定的代码行。如下图所示</p><p><strong>这种效果应该怎么实现呢？</strong></p><ol><li><p>打开 <a href="https://link.juejin.cn/?target=https%3A%2F%2Fgithub.com%2Fqianlongo%2Ffe-handwriting%2Fblob%2Fmaster%2F17.quick-sort.js" target="_blank" rel="noreferrer">github.com/qianlongo/f…</a></p></li><li><p>单击左侧的行号</p></li><li><p>复制链接即可（<a href="https://link.juejin.cn/?target=https%3A%2F%2Fgithub.com%2Fqianlongo%2Ffe-handwriting%2Fblob%2Fmaster%2F17.quick-sort.js%23L8%EF%BC%89" target="_blank" rel="noreferrer">github.com/qianlongo/f…</a></p></li></ol><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/e47b911c41ec434eb964324e44d1c3f3~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp?" alt=""></p><p>相信你一定注意到了链接后的“L8”。是的，咱们可以通过修改“L”+行号链接到所需的代码。</p><h2 id="_4-链接到多行代码" tabindex="-1">4. 链接到多行代码 <a class="header-anchor" href="#_4-链接到多行代码" aria-hidden="true">#</a></h2><p>既然我们可以链接到一行代码，那可以链接到多行吗？当然可以了！！！</p><ol><li><p>打开<a href="https://link.juejin.cn/?target=https%3A%2F%2Fgithub.com%2Fqianlongo%2Ffe-handwriting%2Fblob%2Fmaster%2F17.quick-sort.js" target="_blank" rel="noreferrer">github.com/qianlongo/f…</a></p></li><li><p>按住“shift”键并单击左侧的行号</p></li><li><p>复制链接（<a href="https://link.juejin.cn/?target=https%3A%2F%2Fgithub.com%2Fqianlongo%2Ffe-handwriting%2Fblob%2Fmaster%2F17.quick-sort.js%23L8-L24%EF%BC%89" target="_blank" rel="noreferrer">github.com/qianlongo/f…</a></p></li></ol><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/a4a217cffe814e8887eca41b8279a0b3~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp?" alt=""></p><h2 id="_5-跳转到定义函数的位置" tabindex="-1">5. 跳转到定义函数的位置 <a class="header-anchor" href="#_5-跳转到定义函数的位置" aria-hidden="true">#</a></h2><p>如何快速跳转到定义函数的位置？推荐一个chrome插件，名字是sourcegraph。</p><p>安装插件后，将鼠标放在使用该功能的位置时，会出现一个按钮。单击就可以跳转到定义它的位置。</p><p><img src="https://p6-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/92dd0ca7222545a7a8ad50d513504e6e~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp?" alt=""></p><h2 id="_6-查看快捷键列表" tabindex="-1">6. 查看快捷键列表 <a class="header-anchor" href="#_6-查看快捷键列表" aria-hidden="true">#</a></h2><p>github提供了许多快捷键来帮助我们阅读代码，但记住它们真不是一件简单的事，咱们可以使用“Shift”+“？”显示快捷方式列表。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/4ac4346e500441b5abaca03431e6a5f4~tplv-k3u1fbpfcp-zoom-in-crop-mark:1304:0:0:0.awebp" alt=""></p>',38),o=[p];function l(n,c,h,s,u,d){return i(),t("div",null,o)}const f=e(r,[["render",l]]);export{g as __pageData,f as default};
